class Solution:
    def maximumXOR(self, nums: List[int]) -> int:
        res = 0
        for i in range(30):
            cnt, x = 0, res
            for num in nums:
                if (num >> i) & 1:
                    cnt += 1
                    x |= 1 << i
            if cnt % 2 == 1:
                res = x
        return res
